 11â†’@PublishedApi
 12â†’internal suspend fun <R, T> FlowCollector<R>.combineInternal(
 13â†’    flows: Array<out Flow<T>>,
 14â†’    arrayFactory: () -> Array<T?>?, // Array factory is required to workaround array typing on JVM
 15â†’    transform: suspend FlowCollector<R>.(Array<T>) -> Unit
 16â†’): Unit = flowScope { // flow scope so any cancellation within the source flow will cancel the whole scope
 17â†’    val size = flows.size
 18â†’    if (size == 0) return@flowScope // bail-out for empty input
 19â†’    val latestValues = arrayOfNulls<Any?>(size)
 20â†’    latestValues.fill(UNINITIALIZED) // Smaller bytecode & faster than Array(size) { UNINITIALIZED }
 21â†’    val resultChannel = Channel<Update>(size)
 22â†’    val nonClosed = LocalAtomicInt(size)
 23â†’    var remainingAbsentValues = size
 24â†’    for (i in 0 until size) {
 25â†’        // Coroutine per flow that keeps track of its value and sends result to downstream
 26â†’        launch {
 27â†’            try {
 28â†’                flows[i].collect { value ->
 29â†’                    resultChannel.send(Update(i, value))
 30â†’                    yield() // Emulate fairness, giving each flow chance to emit
 31â†’                }
 32â†’            } finally {
 33â†’                // Close the channel when there is no more flows
 34â†’                if (nonClosed.decrementAndGet() == 0) {
 35â†’                    resultChannel.close()
 36â†’                }
 37â†’            }
 38â†’        }
 39â†’    }
 40â†’
 41â†’    /*
 42â†’     * Batch-receive optimization: read updates in batches, but bail-out
 43â†’     * as soon as we encountered two values from the same source
 44â†’     */
 45â†’    val lastReceivedEpoch = ByteArray(size)
 46â†’    var currentEpoch: Byte = 0
 47â†’    while (true) {
 48â†’        ++currentEpoch
 49â†’        // Start batch
 50â†’        // The very first receive in epoch should be suspending
 51â†’        var element = resultChannel.receiveCatching().getOrNull() ?: break // Channel is closed, nothing to do here
 52â†’        while (true) {
 53â†’            val index = element.index
 54â†’            // Update values
 55â†’            val previous = latestValues[index]
 56â†’            latestValues[index] = element.value
 57â†’            if (previous === UNINITIALIZED) --remainingAbsentValues
 58â†’            // Check epoch
 59â†’            // Received the second value from the same flow in the same epoch -- bail out
 60â†’            if (lastReceivedEpoch[index] == currentEpoch) break
 61â†’            lastReceivedEpoch[index] = currentEpoch
 62â†’            element = resultChannel.tryReceive().getOrNull() ?: break
 63â†’        }
 64â†’
 65â†’        // Process batch result if there is enough data
 66â†’        if (remainingAbsentValues == 0) {
 67â†’            /*
 68â†’             * If arrayFactory returns null, then we can avoid array copy because
 69â†’             * it's our own safe transformer that immediately deconstructs the array
 70â†’             */
 71â†’            val results = arrayFactory()
 72â†’            if (results == null) {
 73â†’                transform(latestValues as Array<T>)
 74â†’            } else {
 75â†’                (latestValues as Array<T?>).copyInto(results)
 76â†’                transform(results as Array<T>)
 77â†’            }
 78â†’        }
 79â†’    }
 80â†’}
