101â†’             */
102â†’            val collectJob = Job()
103â†’            (second as SendChannel<*>).invokeOnClose {
104â†’                // Optimization to avoid AFE allocation when the other flow is done
105â†’                if (collectJob.isActive) collectJob.cancel(AbortFlowException(this@unsafeFlow))
106â†’            }
107â†’
108â†’            try {
109â†’                /*
110â†’                 * Non-trivial undispatched (because we are in the right context and there is no structured concurrency)
111â†’                 * hierarchy:
112â†’                 * -Outer coroutineScope that owns the whole zip process
113â†’                 * - First flow is collected by the child of coroutineScope, collectJob.
114â†’                 *    So it can be safely cancelled as soon as the second flow is done
115â†’                 * - **But** the downstream MUST NOT be cancelled when the second flow is done,
116â†’                 *    so we emit to downstream from coroutineScope job.
117â†’                 * Typically, such hierarchy requires coroutine for collector that communicates
118â†’                 * with coroutines scope via a channel, but it's way too expensive, so
